const cfg = $input.first().json;

const locationLower = cfg.location.toLowerCase();
const isGerman = locationLower.includes('germany') || locationLower.includes('berlin') || locationLower.includes('munich');
const isFinnish = locationLower.includes('finland') || locationLower.includes('helsinki');
const isSpanish = locationLower.includes('spain') || locationLower.includes('madrid');

const languageHint = isGerman ? ' Include German terms.' : 
                     isFinnish ? ' Include Finnish terms.' : 
                     isSpanish ? ' Include Spanish terms.' : 
                     ' Use English terms.';

const prompt = `Analyze this business category for seasonal patterns and conversion signals.\n\nCategory: ${cfg.category}\nLocation: ${cfg.location}\n\nTask 1 - Peak Season Analysis:\nIdentify the 2-4 months (1-12) when this business type has highest demand in this location.\nConsider: local climate, cultural events, holidays, consumer behavior patterns.\n\nTask 2 - Conversion Signals:\nList 5-8 keywords/phrases that indicate a website has online booking or conversion capability.\n${languageHint}\n\nReturn ONLY this JSON structure with NO additional text:\n{\n  "peak_months": [1, 2, 9],\n  "peak_label": "Brief explanation of why these months (max 60 chars)",\n  "conversion_signals": ["keyword1", "keyword2", "keyword3", "keyword4", "keyword5"]\n}`;

return [{
  json: {
    ...cfg,
    signal_prompt: prompt
  }
}];

const cfg = $('Configuration').first().json;
const rawText = $input.first().json.text || $input.first().json.output || "";

let parsedSignals = {
  peak_months: [1, 6, 12],
  peak_label: "Peak demand periods",
  conversion_signals: ['book', 'appointment', 'schedule', 'reserve', 'contact']
};

try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const cleanJson = jsonMatch[0];
    const parsed = JSON.parse(cleanJson);
    if (parsed.peak_months && Array.isArray(parsed.peak_months) && parsed.peak_months.length > 0) {
      parsedSignals.peak_months = parsed.peak_months;
    }
    if (parsed.peak_label && typeof parsed.peak_label === 'string') {
      parsedSignals.peak_label = parsed.peak_label;
    }
    if (parsed.conversion_signals && Array.isArray(parsed.conversion_signals) && parsed.conversion_signals.length > 0) {
      parsedSignals.conversion_signals = parsed.conversion_signals;
    }
  }
} catch (error) {
  console.error('Failed to parse LLM signals, using defaults:', error.message);
}

return [{
  json: {
    category: cfg.category,
    location: cfg.location,
    current_month: cfg.current_month,
    run_date: cfg.run_date,
    season_matrix: { [cfg.category]: { peak_months: parsedSignals.peak_months, label: parsedSignals.peak_label } },
    conversion_signals: { [cfg.category]: parsedSignals.conversion_signals }
  }
}];

const inputItems = $input.all();
const cfg = $('Parse Category Signals ').first().json;

const normalizeFirecrawlResponse = (data) => {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  if (data.data && Array.isArray(data.data)) return data.data;
  if (data.web && Array.isArray(data.web)) return data.web;
  if (data.results && Array.isArray(data.results)) return data.results;
  if (data.data && data.data.web && Array.isArray(data.data.web)) return data.data.web;
  if (data.data && data.data.data && Array.isArray(data.data.data)) return data.data.data;
  return [];
};

return inputItems.map((itemWrapper) => {
  const item = itemWrapper.json;
  const originalData = { ...cfg };
  let results = normalizeFirecrawlResponse(item);
  let ctx = 'No results returned';

  if (results.length > 0) {
    ctx = results.slice(0, 8).map((r, i) => {
      const title = r.title || r.metadata?.title || 'No Title';
      const url = r.url || 'No URL';
      const desc = (r.description || r.markdown || '').substring(0, 300);
      return `[${i+1}] ${title}\nURL: ${url}\nSnippet: ${desc}`;
    }).join('\n\n');
  }

  return { json: { ...originalData, search_context: ctx } };
});

parameters.text:
=Extract exactly 3 local businesses from the search results that match this profile:
- Independent businesses (NOT chains)
- High ratings or strong reputation signals
- Likely need digital improvement

Category: {{ $('Configuration').first().json.category }}
Location: {{ $('Configuration').first().json.location }}

CRITICAL: ONLY extract businesses that are EXACTLY in the "{{ $('Configuration').first().json.category }}" category.
Do NOT include businesses from other categories even if they appear in results.

Search Results:
{{ $json.search_context }}

SELECTION CRITERIA (in priority order):
1. Has reviews/ratings mentioned → signals reputation
2. Independent local business → NOT franchise/chain
3. Weak digital signals → old site, no online booking, basic presence
4. Category match → must be {{ $('Configuration').first().json.category }}

CRITICAL - URL EXTRACTION:
- Extract the SPECIFIC business profile URL from ANY directory (Yelp, Google Maps, Foursquare, TripAdvisor, etc.)
- Must be the BUSINESS PROFILE page
- NOT search results pages
- NOT directory homepages
- Each business MUST have a unique profile URL from a directory site

If you find fewer than 3 businesses, return only what you found.
If search results are empty or contain no {{ $('Configuration').first().json.category }} businesses, return: {"businesses": []}

Return ONLY this JSON structure with NO additional text:
{
  "businesses": [
    {
      "business_name": "Exact name from listing",
      "category": "{{ $('Configuration').first().json.category }}",
      "website_url": "Full directory profile URL (any accepted source)"
    }
  ]
}

