const rawText = $input.first().json.text || "";
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    console.log('No JSON found in response:', rawText.substring(0, 200));
    return [];
  }
  const data = JSON.parse(jsonMatch[0]);
  if (!data.businesses || !Array.isArray(data.businesses)) {
    console.error('Invalid schema from LLM: missing businesses array');
    return [];
  }
  const validBusinesses = data.businesses.filter(b => 
    b.business_name && typeof b.business_name === 'string' &&
    b.website_url && typeof b.website_url === 'string'
  );
  if (validBusinesses.length > 0) {
    return validBusinesses.slice(0, 3).map(b => ({ 
      json: {
        ...b,
        category: b.category ? (b.category.endsWith('s') ? b.category : b.category + 's') : 'Unknown'
      }
    }));
  } else {
    return [];
  }
} catch (error) {
  console.error('JSON Parsing Failed:', error.message);
  return [{ json: { error: "JSON Parsing Failed", message: error.message } }];
}

const parsedLeads = $('Parse Business List').all().map(i => i.json);
const existingLeads = $input.all().map(i => i.json);

const existingNames = new Set(existingLeads.map(l => (l.business_name || '').toLowerCase().trim()));

const newLeads = parsedLeads.filter(l => !existingNames.has((l.business_name || '').toLowerCase().trim()) && !l.error);

if (newLeads.length === 0) {
  return []; // Gracefully stops if there are no new leads to process
}

return newLeads.map(l => ({ json: l }));

try {
  const lead = $('Process Each Lead').item.json;
  if (lead._error) return [{ json: lead }];

  const scrape = $input.first().json || {};
  if (scrape.error) throw new Error(scrape.error.message || 'Website Scrape API Error');

  const scrapeData = scrape.data || scrape;
  return [{
    json: {
      ...lead,
      website_markdown: scrapeData.markdown || '',
      website_screenshot: scrapeData.screenshot || null,
      website_exists: true
    }
  }];
} catch (error) {
  const lead = $('Process Each Lead').item?.json || {};
  return [{ json: { ...lead, _error: error.message, _failed_step: 'website_scrape', website_exists: false } }];
}

const lead = $('Process Each Lead').item.json;
if (lead._error) return [{ json: lead }];
return [{
  json: {
    ...lead,
    website_markdown: '',
    website_screenshot: null,
    website_exists: false
  }
}];

try {
  const lead = $input.first().json;
  if (lead._error) return [{ json: lead }];

  const normalizeFirecrawlResponse = (data) => {
    if (!data) return [];
    if (Array.isArray(data)) return data;
    if (data.data && Array.isArray(data.data)) return data.data;
    if (data.web && Array.isArray(data.web)) return data.web;
    if (data.results && Array.isArray(data.results)) return data.results;
    if (data.data && data.data.web && Array.isArray(data.data.web)) return data.data.web;
    if (data.data && data.data.data && Array.isArray(data.data.data)) return data.data.data;
    return [];
  };

  const results = normalizeFirecrawlResponse(lead);

  let leadDomain = '';
  if (lead.website_url) {
    try { leadDomain = new URL(lead.website_url).hostname.replace('www.', ''); } catch(e) {}
  }

  const leadNameLower = (lead.business_name || '').toLowerCase();
  const skipDomains = ['yelp.com', 'facebook.com', 'instagram.com', 'tripadvisor.com', 'google.com', 'googleusercontent.com'];

  const competitors = results
    .map(r => ({ url: r.url || '', title: r.title || r.metadata?.title || '' }))
    .filter(c => {
      if (!c.url || !c.url.startsWith('http')) return false;
      if (leadDomain && c.url.includes(leadDomain)) return false;
      if (leadNameLower.length > 4 && c.title.toLowerCase().includes(leadNameLower)) return false;
      try {
        const hostname = new URL(c.url).hostname.replace('www.', '');
        if (skipDomains.some(d => hostname.includes(d))) return false;
      } catch(e) { return false; }
      return true;
    })
    .slice(0, 3);

  return [{ json: { ...lead, data: undefined, results: undefined, competitor_urls: competitors.map(c => c.url) } }];
} catch (error) {
  const lead = $input.first().json || {};
  return [{ json: { ...lead, _error: error.message, _failed_step: 'filter_competitors' } }];
}

try {
  const lead = $input.first().json;
  if (lead._error) return [{ json: lead }];

  const urls = lead.competitor_urls || [];
  if (urls.length === 0) return [{ json: { ...lead, _skip_comp: true, _comp_idx: 0, _total: 0 } }];

  return urls.map((url, idx) => ({
    json: { _parent_lead: lead, _comp_url: url, _comp_idx: idx, _total: urls.length }
  }));
} catch (error) {
  const lead = $input.first().json || {};
  return [{ json: { ...lead, _error: error.message, _failed_step: 'split_competitors' } }];
}

try {
  const items = $input.all();
  if (!items.length) return [];
  if (items[0].json._error) return [{ json: items[0].json }];

  if (items[0].json._skip_comp) {
    const { _skip_comp, _comp_idx, _total, ...cleanLead } = items[0].json;
    return [{ json: { ...cleanLead, competitor_markdowns: [] } }];
  }

  const parentLead = items[0].json._parent_lead;
  const validItems = items.filter(i => typeof i.json._comp_idx === 'number');

  if (validItems.length !== items.length) {
    console.error(`Missing competitor indexes: expected ${items.length}, got ${validItems.length}`);
  }

  const sorted = validItems.sort((a, b) => a.json._comp_idx - b.json._comp_idx);
  const markdowns = sorted.map(i => (i.json.data || i.json).markdown || '');

  return [{ json: { ...parentLead, competitor_markdowns: markdowns } }];
} catch (error) {
  const parentLead = $input.all()[0]?.json?._parent_lead || {};
  return [{ json: { ...parentLead, _error: error.message, _failed_step: 'merge_competitors' } }];
}

try {
  const lead = $input.first().json;
  if (lead._error) return [{ json: lead }];

  const normalizeFirecrawlResponse = (data) => {
    if (!data) return [];
    if (Array.isArray(data)) return data;
    if (data.data && Array.isArray(data.data)) return data.data;
    if (data.web && Array.isArray(data.web)) return data.web;
    if (data.results && Array.isArray(data.results)) return data.results;
    if (data.data && data.data.web && Array.isArray(data.data.web)) return data.data.web;
    if (data.data && data.data.data && Array.isArray(data.data.data)) return data.data.data;
    return [];
  };

  const results = normalizeFirecrawlResponse(lead);
  const snippets = results
    .slice(0, 5)
    .map(r => (r.description || r.markdown || '').substring(0, 500))
    .filter(t => t.length > 30);

  return [{ json: { ...lead, data: undefined, results: undefined, review_snippets: snippets } }];
} catch (error) {
  const lead = $input.first().json || {};
  return [{ json: { ...lead, _error: error.message, _failed_step: 'extract_reviews' } }];
}

parameters.text:
=Extract specific services that customers are praising from these reviews.

Business: {{ $json.business_name }}
Category: {{ $json.category }}

Reviews:
{{ ($json.review_snippets || []).join('\n---\n').substring(0, 2500) }}

RULES:
1. Only extract CONCRETE SERVICES that customers explicitly praise or describe positively
2. Use the exact terminology from reviews when possible (e.g., "balayage" not "hair coloring")
3. Ignore: staff names, atmosphere comments, parking, prices, general praise ("great service")
4. Extract service names only - no descriptions or qualifiers
5. Return empty array if no specific services are mentioned

Return ONLY valid JSON in this exact format:
{
  "services": ["service1", "service2"]
}

parameters.jsCode:
try {
  const lead = $('Extract Review Snippets').item?.json || $input.first().json || {};
  if (lead._error) return [{ json: lead }];

  const openaiResp = $input.first().json || {};
  let praisedServices = [];
  try {
    const content = openaiResp?.choices?.[0]?.message?.content || openaiResp?.text || '{}';
    const parsed = JSON.parse(content);
    praisedServices = Array.isArray(parsed.services) ? parsed.services : [];
  } catch(e) { praisedServices = []; }

  const currentMonth = parseInt(lead.current_month) || (new Date().getMonth() + 1);
  const category = lead.category || 'Unknown';
  const seasonMatrix = lead.season_matrix || {};
  const conversionSignals = lead.conversion_signals || {};

  const mkdwn = (lead.website_markdown || '').toLowerCase();
  const websiteExists = !!lead.website_exists;
  const hasHttps = lead.website_url ? lead.website_url.startsWith('https') : false;
  const hasMobileViewport = mkdwn.includes('viewport');
  const copyrightMatch = mkdwn.match(/copyright[^\d]*(20\d{2})|©\s*(20\d{2})/);
  const copyrightYear = copyrightMatch ? parseInt(copyrightMatch[1] || copyrightMatch[2]) : null;
  const hasOldCopyright = copyrightYear ? copyrightYear < 2020 : false;

  const convSignals = conversionSignals[category] || [];
  const hasConversionPath = convSignals.some(s => mkdwn.includes(s.toLowerCase()));

  const cmsMap = { WordPress: ['wp-content','wp-includes'], Wix: ['wix.com','wixsite'], Squarespace: ['squarespace'], Jimdo: ['jimdo'], Joomla: ['joomla'] };
  let detectedCms = null;
  for (const [cms, sigs] of Object.entries(cmsMap)) {
    if (sigs.some(s => mkdwn.includes(s))) { detectedCms = cms; break; }
  }

  const revenueLeak = praisedServices.filter(svc =>
    svc && typeof svc === 'string' && !mkdwn.includes(svc.toLowerCase())
  );

  const compMarkdowns = lead.competitor_markdowns || [];
  let competitorsWithConversion = 0;
  for (const md of compMarkdowns) {
    if (convSignals.some(s => (md || '').toLowerCase().includes(s.toLowerCase()))) {
      competitorsWithConversion++;
    }
  }

  const seasonData = seasonMatrix[category];
  let seasonalUrgency = null;
  let weeksToPeak = null;
  let peakLabel = null;
  if (seasonData && Array.isArray(seasonData.peak_months)) {
    peakLabel = seasonData.label;
    const diffs = seasonData.peak_months.map(pm => {
      let d = pm - currentMonth;
      if (d <= 0) d += 12;
      return d;
    });
    const minMonths = Math.min(...diffs);
    weeksToPeak = Math.round(minMonths * 4.33);
    seasonalUrgency = minMonths <= 2 ? 'CRITICAL' : minMonths <= 4 ? 'HIGH' : 'MEDIUM';
  }

  const reviewCount = parseInt(lead.directory_review_count) || 0;
  const rating = parseFloat(lead.directory_rating) || 0;

  const reputationScore = Math.min(100, (Math.min(reviewCount, 200) / 200 * 60) + (rating / 5 * 40));

  let digitalScore = 0;
  if (websiteExists) {
    if (hasHttps) digitalScore += 20;
    if (hasMobileViewport) digitalScore += 20;
    if (!hasOldCopyright) digitalScore += 15;
    if (hasConversionPath) digitalScore += 30;
    if (!detectedCms || !['Wix','Jimdo','Joomla'].includes(detectedCms)) digitalScore += 15;
  }

  const mismatchRaw = reputationScore - (digitalScore * 0.6);
  const mismatchScore = Math.max(0, Math.min(100, Math.round(mismatchRaw) + 40));

  let opportunityScore = mismatchScore;
  if (revenueLeak.length > 0) opportunityScore += 15;
  if (competitorsWithConversion > 0) opportunityScore += 10;
  if (seasonalUrgency === 'CRITICAL') opportunityScore += 10;
  else if (seasonalUrgency === 'HIGH') opportunityScore += 5;
  opportunityScore = Math.min(100, Math.round(opportunityScore));

  const opportunityTier = opportunityScore >= 75 ? 'High' : opportunityScore >= 50 ? 'Medium' : 'Low';

  const objectiveIssues = [];
  const heuristicIssues = [];
  if (!websiteExists) objectiveIssues.push('No website found in public listings');
  else {
    if (!hasHttps) objectiveIssues.push('No HTTPS');
    if (!hasMobileViewport) objectiveIssues.push('No mobile viewport meta tag');
    if (hasOldCopyright) objectiveIssues.push(`Copyright year ${copyrightYear}`);
    if (!hasConversionPath) objectiveIssues.push(`No ${category} conversion path`);
  }
  if (detectedCms && ['Wix','Jimdo','Joomla'].includes(detectedCms)) heuristicIssues.push(`Built with ${detectedCms} — may indicate template-based site`);
  if (hasOldCopyright) heuristicIssues.push('Site freshness appears low');

  const websiteIssues = [
    ...objectiveIssues.map(i => `[Objective] ${i}`),
    ...heuristicIssues.map(i => `[Heuristic] ${i}`)
  ].join('; ') || 'None detected';

  const observedFacts = [];
  const heuristicAssessment = [];
  if (!websiteExists) observedFacts.push('No website found in public directory listings');
  else {
    observedFacts.push(`Website: ${lead.website_url}`);
    observedFacts.push(hasHttps ? 'HTTPS present' : 'HTTPS absent');
    observedFacts.push(hasMobileViewport ? 'Mobile viewport tag present' : 'Mobile viewport tag absent');
    if (copyrightYear) observedFacts.push(`Footer copyright: ${copyrightYear}`);
    observedFacts.push(hasConversionPath ? `${category} conversion path detected` : `No ${category} conversion path`);
    if (detectedCms) observedFacts.push(`CMS: ${detectedCms}`);
  }
  if (reviewCount > 0) observedFacts.push(`${reviewCount} public reviews at ${rating} stars average`);
  if (hasOldCopyright) heuristicAssessment.push(`Site freshness low (~${copyrightYear})`);
  if (detectedCms && ['Wix','Jimdo','Joomla'].includes(detectedCms)) heuristicAssessment.push(`${detectedCms} template suggests DIY build`);
  if (competitorsWithConversion > 0) heuristicAssessment.push(`${competitorsWithConversion} nearby competitors appear more digitally capable`);
  if (reputationScore > 70 && digitalScore < 40) heuristicAssessment.push('Strong reputation paired with weak digital execution');

  let pitchHook, pitchAngle;
  if (revenueLeak.length > 0) {
    pitchAngle = 'Revenue Leak';
    pitchHook = `Your customers are telling Google you do exceptional ${revenueLeak[0]}. Your website does not know that word exists.`;
  } else if (!websiteExists) {
    pitchAngle = 'Missing Presence';
    pitchHook = `You have ${reviewCount} reviews and ${rating} stars. Every person who finds you online and wants to book has nowhere to go.`;
  } else if (!hasConversionPath) {
    pitchAngle = 'Missing Conversion';
    pitchHook = `You have ${reviewCount} strong reviews and no way for a new customer to take action after reading them.`;
  } else if (competitorsWithConversion > 0) {
    pitchAngle = 'Competitive Pressure';
    pitchHook = `${competitorsWithConversion} of your nearest competitors have online booking. You are the only one in this cluster without it.`;
  } else if (seasonalUrgency === 'CRITICAL') {
    pitchAngle = 'Seasonal Timing';
    pitchHook = `${peakLabel} is ${weeksToPeak} weeks away. Now is the window where a website upgrade pays for itself fastest.`;
  } else {
    pitchAngle = 'General Mismatch';
    pitchHook = `Strong reputation with ${reviewCount} reviews — your digital presence is not converting that trust into new bookings.`;
  }

  const whyPoints = [
    !websiteExists ? 'No website in public listings' : null,
    revenueLeak.length > 0 ? `Revenue leak: praised services absent from website (${revenueLeak.slice(0,2).join(', ')})` : null,
    !hasConversionPath && websiteExists ? `No ${category} conversion path` : null,
    competitorsWithConversion > 0 ? `${competitorsWithConversion} nearby competitors stronger digitally` : null,
    seasonalUrgency === 'CRITICAL' ? `Peak season in ~${weeksToPeak} weeks` : null
  ].filter(Boolean);

  return [{ json: {
    run_date: lead.run_date,
    business_name: lead.business_name,
    category,
    address: lead.address || 'not listed',
    phone: lead.phone || 'not listed',
    website: lead.website_url || 'none',
    website_issues: websiteIssues,
    services_listed: Array.isArray(lead.services_listed) ? lead.services_listed.join(', ') : 'not listed',
    opportunity_score: opportunityTier,
    opportunity_score_numeric: opportunityScore,
    why_a_lead: whyPoints.join('. '),
    source_links: lead.directory_source_url || 'not listed',
    public_rating: rating,
    review_count: reviewCount,
    tech_signals: detectedCms || 'not detected',
    freshness_signal: copyrightYear ? `Footer copyright ${copyrightYear}` : 'not detected',
    competitor_urls: (lead.competitor_urls || []).join(', '),
    competitors_with_booking: competitorsWithConversion,
    website_screenshot: lead.website_screenshot || null,
    praised_services: praisedServices.join(', ') || 'none extracted',
    revenue_leak_services: revenueLeak.join(', ') || 'none',
    revenue_leak_detected: revenueLeak.length > 0,
    seasonal_urgency: seasonalUrgency || 'not applicable',
    weeks_to_peak_season: weeksToPeak || null,
    peak_season_context: peakLabel || null,
    reputation_score: parseFloat(reputationScore.toFixed(1)),
    digital_score: parseFloat(digitalScore.toFixed(1)),
    mismatch_score: mismatchScore,
    pitch_angle: pitchAngle,
    pitch_hook: pitchHook,
    observed_facts: observedFacts.join('. '),
    heuristic_assessment: heuristicAssessment.join('. ') || 'No heuristic flags'
  }}];
} catch (error) {
  const lead = $('Extract Review Snippets').item?.json || $input.first().json || {};
  return [{ json: { ...lead, _error: error.message, _failed_step: 'mismatch_engine' } }];
}

const aggregated = $('Aggregate All Leads').first().json.data || $('Aggregate All Leads').first().json || [];
const leadsArray = Array.isArray(aggregated) ? aggregated : [aggregated];

const newLeads = leadsArray
  .filter(l => l && l.business_name && !l._error) 
  .sort((a, b) => (b.opportunity_score_numeric || 0) - (a.opportunity_score_numeric || 0))
  .slice(0, 10);

if (newLeads.length === 0) return [{ json: { _no_new_leads: true } }];
return newLeads.map(l => ({ json: l }));

const items = $input.all();
const validLeads = items.filter(item => !item.json._no_new_leads && !item.json._error);
if (validLeads.length === 0) return [];
return validLeads;

const aggregated = $('Aggregate for Report').first().json.data || [];
if (aggregated.length === 0) return [{ json: { _no_new_leads: true } }];
return aggregated.map(l => ({ json: { ...l } }));
